     1→/*!
     2→Defines a very high level "search worker" abstraction.
     3→
     4→A search worker manages the high level interaction points between the matcher
     5→(i.e., which regex engine is used), the searcher (i.e., how data is actually
     6→read and matched using the regex engine) and the printer. For example, the
     7→search worker is where things like preprocessors or decompression happens.
     8→*/
     9→
    10→use std::{io, path::Path};
    11→
    12→use {grep::matcher::Matcher, termcolor::WriteColor};
    13→
    14→/// The configuration for the search worker.
    15→///
    16→/// Among a few other things, the configuration primarily controls the way we
    17→/// show search results to users at a very high level.
    18→#[derive(Clone, Debug)]
    19→struct Config {
    20→    preprocessor: Option<std::path::PathBuf>,
    21→    preprocessor_globs: ignore::overrides::Override,
    22→    search_zip: bool,
    23→    binary_implicit: grep::searcher::BinaryDetection,
    24→    binary_explicit: grep::searcher::BinaryDetection,
    25→}
    26→
    27→impl Default for Config {
    28→    fn default() -> Config {
    29→        Config {
    30→            preprocessor: None,
    31→            preprocessor_globs: ignore::overrides::Override::empty(),
    32→            search_zip: false,
    33→            binary_implicit: grep::searcher::BinaryDetection::none(),
    34→            binary_explicit: grep::searcher::BinaryDetection::none(),
    35→        }
    36→    }
    37→}
    38→
    39→/// A builder for configuring and constructing a search worker.
    40→#[derive(Clone, Debug)]
    41→pub(crate) struct SearchWorkerBuilder {
    42→    config: Config,
    43→    command_builder: grep::cli::CommandReaderBuilder,
    44→}
    45→
    46→impl Default for SearchWorkerBuilder {
    47→    fn default() -> SearchWorkerBuilder {
    48→        SearchWorkerBuilder::new()
    49→    }
    50→}
    51→
    52→impl SearchWorkerBuilder {
    53→    /// Create a new builder for configuring and constructing a search worker.
    54→    pub(crate) fn new() -> SearchWorkerBuilder {
    55→        let mut command_builder = grep::cli::CommandReaderBuilder::new();
    56→        command_builder.async_stderr(true);
    57→
    58→        SearchWorkerBuilder { config: Config::default(), command_builder }
    59→    }
    60→
    61→    /// Create a new search worker using the given searcher, matcher and
    62→    /// printer.
    63→    pub(crate) fn build<W: WriteColor>(
    64→        &self,
    65→        matcher: PatternMatcher,
    66→        searcher: grep::searcher::Searcher,
    67→        printer: Printer<W>,
    68→    ) -> SearchWorker<W> {
    69→        let config = self.config.clone();
    70→        let command_builder = self.command_builder.clone();
    71→        let decomp_builder = config.search_zip.then(|| {
    72→            let mut decomp_builder =
    73→                grep::cli::DecompressionReaderBuilder::new();
    74→            decomp_builder.async_stderr(true);
    75→            decomp_builder
    76→        });
    77→        SearchWorker {
    78→            config,
    79→            command_builder,
    80→            decomp_builder,
    81→            matcher,
    82→            searcher,
    83→            printer,
    84→        }
    85→    }
    86→
    87→    /// Set the path to a preprocessor command.
    88→    ///
    89→    /// When this is set, instead of searching files directly, the given
    90→    /// command will be run with the file path as the first argument, and the
    91→    /// output of that command will be searched instead.
    92→    pub(crate) fn preprocessor(
    93→        &mut self,
    94→        cmd: Option<std::path::PathBuf>,
    95→    ) -> anyhow::Result<&mut SearchWorkerBuilder> {
    96→        if let Some(ref prog) = cmd {
    97→            let bin = grep::cli::resolve_binary(prog)?;
    98→            self.config.preprocessor = Some(bin);
    99→        } else {
   100→            self.config.preprocessor = None;
   101→        }
   102→        Ok(self)
   103→    }
   104→
   105→    /// Set the globs for determining which files should be run through the
   106→    /// preprocessor. By default, with no globs and a preprocessor specified,
   107→    /// every file is run through the preprocessor.
   108→    pub(crate) fn preprocessor_globs(
   109→        &mut self,
   110→        globs: ignore::overrides::Override,
   111→    ) -> &mut SearchWorkerBuilder {
   112→        self.config.preprocessor_globs = globs;
   113→        self
   114→    }
   115→
   116→    /// Enable the decompression and searching of common compressed files.
   117→    ///
   118→    /// When enabled, if a particular file path is recognized as a compressed
   119→    /// file, then it is decompressed before searching.
   120→    ///
   121→    /// Note that if a preprocessor command is set, then it overrides this
   122→    /// setting.
   123→    pub(crate) fn search_zip(
   124→        &mut self,
   125→        yes: bool,
   126→    ) -> &mut SearchWorkerBuilder {
   127→        self.config.search_zip = yes;
   128→        self
   129→    }
   130→
   131→    /// Set the binary detection that should be used when searching files
   132→    /// found via a recursive directory search.
   133→    ///
   134→    /// Generally, this binary detection may be
   135→    /// `grep::searcher::BinaryDetection::quit` if we want to skip binary files
   136→    /// completely.
   137→    ///
   138→    /// By default, no binary detection is performed.
   139→    pub(crate) fn binary_detection_implicit(
   140→        &mut self,
   141→        detection: grep::searcher::BinaryDetection,
   142→    ) -> &mut SearchWorkerBuilder {
   143→        self.config.binary_implicit = detection;
   144→        self
   145→    }
   146→
   147→    /// Set the binary detection that should be used when searching files
   148→    /// explicitly supplied by an end user.
   149→    ///
   150→    /// Generally, this binary detection should NOT be
   151→    /// `grep::searcher::BinaryDetection::quit`, since we never want to
   152→    /// automatically filter files supplied by the end user.
   153→    ///
   154→    /// By default, no binary detection is performed.
   155→    pub(crate) fn binary_detection_explicit(
   156→        &mut self,
   157→        detection: grep::searcher::BinaryDetection,
   158→    ) -> &mut SearchWorkerBuilder {
   159→        self.config.binary_explicit = detection;
   160→        self
   161→    }
   162→}
   163→
   164→/// The result of executing a search.
   165→///
   166→/// Generally speaking, the "result" of a search is sent to a printer, which
   167→/// writes results to an underlying writer such as stdout or a file. However,
   168→/// every search also has some aggregate statistics or meta data that may be
   169→/// useful to higher level routines.
   170→#[derive(Clone, Debug, Default)]
   171→pub(crate) struct SearchResult {
   172→    has_match: bool,
   173→    stats: Option<grep::printer::Stats>,
   174→}
   175→
   176→impl SearchResult {
   177→    /// Whether the search found a match or not.
   178→    pub(crate) fn has_match(&self) -> bool {
   179→        self.has_match
   180→    }
   181→
   182→    /// Return aggregate search statistics for a single search, if available.
   183→    ///
   184→    /// It can be expensive to compute statistics, so these are only present
   185→    /// if explicitly enabled in the printer provided by the caller.
   186→    pub(crate) fn stats(&self) -> Option<&grep::printer::Stats> {
   187→        self.stats.as_ref()
   188→    }
   189→}
   190→
   191→/// The pattern matcher used by a search worker.
   192→#[derive(Clone, Debug)]
   193→pub(crate) enum PatternMatcher {
   194→    RustRegex(grep::regex::RegexMatcher),
   195→    #[cfg(feature = "pcre2")]
   196→    PCRE2(grep::pcre2::RegexMatcher),
   197→}
   198→
   199→/// The printer used by a search worker.
   200→///
   201→/// The `W` type parameter refers to the type of the underlying writer.
   202→#[derive(Clone, Debug)]
   203→pub(crate) enum Printer<W> {
   204→    /// Use the standard printer, which supports the classic grep-like format.
   205→    Standard(grep::printer::Standard<W>),
   206→    /// Use the summary printer, which supports aggregate displays of search
   207→    /// results.
   208→    Summary(grep::printer::Summary<W>),
   209→    /// A JSON printer, which emits results in the JSON Lines format.
   210→    JSON(grep::printer::JSON<W>),
   211→}
   212→
   213→impl<W: WriteColor> Printer<W> {
   214→    /// Return a mutable reference to the underlying printer's writer.
   215→    pub(crate) fn get_mut(&mut self) -> &mut W {
   216→        match *self {
   217→            Printer::Standard(ref mut p) => p.get_mut(),
   218→            Printer::Summary(ref mut p) => p.get_mut(),
   219→            Printer::JSON(ref mut p) => p.get_mut(),
   220→        }
   221→    }
   222→}
   223→
   224→/// A worker for executing searches.
   225→///
   226→/// It is intended for a single worker to execute many searches, and is
   227→/// generally intended to be used from a single thread. When searching using
   228→/// multiple threads, it is better to create a new worker for each thread.
   229→#[derive(Clone, Debug)]
   230→pub(crate) struct SearchWorker<W> {
   231→    config: Config,
   232→    command_builder: grep::cli::CommandReaderBuilder,
   233→    /// This is `None` when `search_zip` is not enabled, since in this case it
   234→    /// can never be used. We do this because building the reader can sometimes
   235→    /// do non-trivial work (like resolving the paths of decompression binaries
   236→    /// on Windows).
   237→    decomp_builder: Option<grep::cli::DecompressionReaderBuilder>,
   238→    matcher: PatternMatcher,
   239→    searcher: grep::searcher::Searcher,
   240→    printer: Printer<W>,
   241→}
   242→
   243→impl<W: WriteColor> SearchWorker<W> {
   244→    /// Execute a search over the given haystack.
   245→    pub(crate) fn search(
   246→        &mut self,
   247→        haystack: &crate::haystack::Haystack,
   248→    ) -> io::Result<SearchResult> {
   249→        let bin = if haystack.is_explicit() {
   250→            self.config.binary_explicit.clone()
   251→        } else {
   252→            self.config.binary_implicit.clone()
   253→        };
   254→        let path = haystack.path();
   255→        log::trace!("{}: binary detection: {:?}", path.display(), bin);
   256→
   257→        self.searcher.set_binary_detection(bin);
   258→        if haystack.is_stdin() {
   259→            self.search_reader(path, &mut io::stdin().lock())
   260→        } else if self.should_preprocess(path) {
   261→            self.search_preprocessor(path)
   262→        } else if self.should_decompress(path) {
   263→            self.search_decompress(path)
   264→        } else {
   265→            self.search_path(path)
   266→        }
   267→    }
   268→
   269→    /// Return a mutable reference to the underlying printer.
   270→    pub(crate) fn printer(&mut self) -> &mut Printer<W> {
   271→        &mut self.printer
   272→    }
   273→
   274→    /// Returns true if and only if the given file path should be
   275→    /// decompressed before searching.
   276→    fn should_decompress(&self, path: &Path) -> bool {
   277→        self.decomp_builder.as_ref().is_some_and(|decomp_builder| {
   278→            decomp_builder.get_matcher().has_command(path)
   279→        })
   280→    }
   281→
   282→    /// Returns true if and only if the given file path should be run through
   283→    /// the preprocessor.
   284→    fn should_preprocess(&self, path: &Path) -> bool {
   285→        if !self.config.preprocessor.is_some() {
   286→            return false;
   287→        }
   288→        if self.config.preprocessor_globs.is_empty() {
   289→            return true;
   290→        }
   291→        !self.config.preprocessor_globs.matched(path, false).is_ignore()
   292→    }
   293→
   294→    /// Search the given file path by first asking the preprocessor for the
   295→    /// data to search instead of opening the path directly.
   296→    fn search_preprocessor(
   297→        &mut self,
   298→        path: &Path,
   299→    ) -> io::Result<SearchResult> {
   300→        use std::{fs::File, process::Stdio};
   301→
   302→        let bin = self.config.preprocessor.as_ref().unwrap();
   303→        let mut cmd = std::process::Command::new(bin);
   304→        cmd.arg(path).stdin(Stdio::from(File::open(path)?));
   305→
   306→        let mut rdr = self.command_builder.build(&mut cmd).map_err(|err| {
   307→            io::Error::new(
   308→                io::ErrorKind::Other,
   309→                format!(
   310→                    "preprocessor command could not start: '{cmd:?}': {err}",
   311→                ),
   312→            )
   313→        })?;
   314→        let result = self.search_reader(path, &mut rdr).map_err(|err| {
   315→            io::Error::new(
   316→                io::ErrorKind::Other,
   317→                format!("preprocessor command failed: '{cmd:?}': {err}"),
   318→            )
   319→        });
   320→        let close_result = rdr.close();
   321→        let search_result = result?;
   322→        close_result?;
   323→        Ok(search_result)
   324→    }
   325→
   326→    /// Attempt to decompress the data at the given file path and search the
   327→    /// result. If the given file path isn't recognized as a compressed file,
   328→    /// then search it without doing any decompression.
   329→    fn search_decompress(&mut self, path: &Path) -> io::Result<SearchResult> {
   330→        let Some(ref decomp_builder) = self.decomp_builder else {
   331→            return self.search_path(path);
   332→        };
   333→        let mut rdr = decomp_builder.build(path)?;
   334→        let result = self.search_reader(path, &mut rdr);
   335→        let close_result = rdr.close();
   336→        let search_result = result?;
   337→        close_result?;
   338→        Ok(search_result)
   339→    }
   340→
   341→    /// Search the contents of the given file path.
   342→    fn search_path(&mut self, path: &Path) -> io::Result<SearchResult> {
   343→        use self::PatternMatcher::*;
   344→
   345→        let (searcher, printer) = (&mut self.searcher, &mut self.printer);
   346→        match self.matcher {
   347→            RustRegex(ref m) => search_path(m, searcher, printer, path),
   348→            #[cfg(feature = "pcre2")]
   349→            PCRE2(ref m) => search_path(m, searcher, printer, path),
   350→        }
   351→    }
   352→
   353→    /// Executes a search on the given reader, which may or may not correspond
   354→    /// directly to the contents of the given file path. Instead, the reader
   355→    /// may actually cause something else to be searched (for example, when
   356→    /// a preprocessor is set or when decompression is enabled). In those
   357→    /// cases, the file path is used for visual purposes only.
   358→    ///
   359→    /// Generally speaking, this method should only be used when there is no
   360→    /// other choice. Searching via `search_path` provides more opportunities
   361→    /// for optimizations (such as memory maps).
   362→    fn search_reader<R: io::Read>(
   363→        &mut self,
   364→        path: &Path,
   365→        rdr: &mut R,
   366→    ) -> io::Result<SearchResult> {
   367→        use self::PatternMatcher::*;
   368→
   369→        let (searcher, printer) = (&mut self.searcher, &mut self.printer);
   370→        match self.matcher {
   371→            RustRegex(ref m) => search_reader(m, searcher, printer, path, rdr),
   372→            #[cfg(feature = "pcre2")]
   373→            PCRE2(ref m) => search_reader(m, searcher, printer, path, rdr),
   374→        }
   375→    }
   376→}
   377→
   378→/// Search the contents of the given file path using the given matcher,
   379→/// searcher and printer.
   380→fn search_path<M: Matcher, W: WriteColor>(
   381→    matcher: M,
   382→    searcher: &mut grep::searcher::Searcher,
   383→    printer: &mut Printer<W>,
   384→    path: &Path,
   385→) -> io::Result<SearchResult> {
   386→    match *printer {
   387→        Printer::Standard(ref mut p) => {
   388→            let mut sink = p.sink_with_path(&matcher, path);
   389→            searcher.search_path(&matcher, path, &mut sink)?;
   390→            Ok(SearchResult {
   391→                has_match: sink.has_match(),
   392→                stats: sink.stats().map(|s| s.clone()),
   393→            })
   394→        }
   395→        Printer::Summary(ref mut p) => {
   396→            let mut sink = p.sink_with_path(&matcher, path);
   397→            searcher.search_path(&matcher, path, &mut sink)?;
   398→            Ok(SearchResult {
   399→                has_match: sink.has_match(),
   400→                stats: sink.stats().map(|s| s.clone()),
   401→            })
   402→        }
   403→        Printer::JSON(ref mut p) => {
   404→            let mut sink = p.sink_with_path(&matcher, path);
   405→            searcher.search_path(&matcher, path, &mut sink)?;
   406→            Ok(SearchResult {
   407→                has_match: sink.has_match(),
   408→                stats: Some(sink.stats().clone()),
   409→            })
   410→        }
   411→    }
   412→}
   413→
   414→/// Search the contents of the given reader using the given matcher, searcher
   415→/// and printer.
   416→fn search_reader<M: Matcher, R: io::Read, W: WriteColor>(
   417→    matcher: M,
   418→    searcher: &mut grep::searcher::Searcher,
   419→    printer: &mut Printer<W>,
   420→    path: &Path,
   421→    mut rdr: R,
   422→) -> io::Result<SearchResult> {
   423→    match *printer {
   424→        Printer::Standard(ref mut p) => {
   425→            let mut sink = p.sink_with_path(&matcher, path);
   426→            searcher.search_reader(&matcher, &mut rdr, &mut sink)?;
   427→            Ok(SearchResult {
   428→                has_match: sink.has_match(),
   429→                stats: sink.stats().map(|s| s.clone()),
   430→            })
   431→        }
   432→        Printer::Summary(ref mut p) => {
   433→            let mut sink = p.sink_with_path(&matcher, path);
   434→            searcher.search_reader(&matcher, &mut rdr, &mut sink)?;
   435→            Ok(SearchResult {
   436→                has_match: sink.has_match(),
   437→                stats: sink.stats().map(|s| s.clone()),
   438→            })
   439→        }
   440→        Printer::JSON(ref mut p) => {
   441→            let mut sink = p.sink_with_path(&matcher, path);
   442→            searcher.search_reader(&matcher, &mut rdr, &mut sink)?;
   443→            Ok(SearchResult {
   444→                has_match: sink.has_match(),
   445→                stats: Some(sink.stats().clone()),
   446→            })
   447→        }
   448→    }
   449→}
