   515→    impl TempDir {
   516→        /// Create a new empty temporary directory under the system's configured
   517→        /// temporary directory.
   518→        pub fn new() -> Result<TempDir> {
   519→            use std::sync::atomic::{AtomicUsize, Ordering};
   520→
   521→            static TRIES: usize = 100;
   522→            static COUNTER: AtomicUsize = AtomicUsize::new(0);
   523→
   524→            let tmpdir = env::temp_dir();
   525→            for _ in 0..TRIES {
   526→                let count = COUNTER.fetch_add(1, Ordering::Relaxed);
   527→                let path = tmpdir.join("rust-ignore").join(count.to_string());
   528→                if path.is_dir() {
   529→                    continue;
   530→                }
   531→                fs::create_dir_all(&path).map_err(|e| {
   532→                    err!("failed to create {}: {}", path.display(), e)
   533→                })?;
   534→                return Ok(TempDir(path));
   535→            }
   536→            Err(err!("failed to create temp dir after {} tries", TRIES))
   537→        }
