    42→/// Then, as it was, then again it will be.
    43→fn main() -> ExitCode {
    44→    match run(flags::parse()) {
    45→        Ok(code) => code,
    46→        Err(err) => {
    47→            // Look for a broken pipe error. In this case, we generally want
    48→            // to exit "gracefully" with a success exit code. This matches
    49→            // existing Unix convention. We need to handle this explicitly
    50→            // since the Rust runtime doesn't ask for PIPE signals, and thus
    51→            // we get an I/O error instead. Traditional C Unix applications
    52→            // quit by getting a PIPE signal that they don't handle, and thus
    53→            // the unhandled signal causes the process to unceremoniously
    54→            // terminate.
    55→            for cause in err.chain() {
    56→                if let Some(ioerr) = cause.downcast_ref::<std::io::Error>() {
    57→                    if ioerr.kind() == std::io::ErrorKind::BrokenPipe {
    58→                        return ExitCode::from(0);
    59→                    }
    60→                }
    61→            }
    62→            eprintln_locked!("{:#}", err);
    63→            ExitCode::from(2)
    64→        }
    65→    }
    66→}
