    68→/// The main entry point for ripgrep.
    69→///
    70→/// The given parse result determines ripgrep's behavior. The parse
    71→/// result should be the result of parsing CLI arguments in a low level
    72→/// representation, and then followed by an attempt to convert them into a
    73→/// higher level representation. The higher level representation has some nicer
    74→/// abstractions, for example, instead of representing the `-g/--glob` flag
    75→/// as a `Vec<String>` (as in the low level representation), the globs are
    76→/// converted into a single matcher.
    77→fn run(result: crate::flags::ParseResult<HiArgs>) -> anyhow::Result<ExitCode> {
    78→    use crate::flags::{Mode, ParseResult};
    79→
    80→    let args = match result {
    81→        ParseResult::Err(err) => return Err(err),
    82→        ParseResult::Special(mode) => return special(mode),
    83→        ParseResult::Ok(args) => args,
    84→    };
    85→    let matched = match args.mode() {
    86→        Mode::Search(_) if !args.matches_possible() => false,
    87→        Mode::Search(mode) if args.threads() == 1 => search(&args, mode)?,
    88→        Mode::Search(mode) => search_parallel(&args, mode)?,
    89→        Mode::Files if args.threads() == 1 => files(&args)?,
    90→        Mode::Files => files_parallel(&args)?,
    91→        Mode::Types => return types(&args),
    92→        Mode::Generate(mode) => return generate(mode),
    93→    };
    94→    Ok(if matched && (args.quiet() || !messages::errored()) {
    95→        ExitCode::from(0)
    96→    } else if messages::errored() {
    97→        ExitCode::from(2)
    98→    } else {
    99→        ExitCode::from(1)
   100→    })
   101→}
