   103→/// The top-level entry point for single-threaded search.
   104→///
   105→/// This recursively steps through the file list (current directory by default)
   106→/// and searches each file sequentially.
   107→fn search(args: &HiArgs, mode: SearchMode) -> anyhow::Result<bool> {
   108→    let started_at = std::time::Instant::now();
   109→    let haystack_builder = args.haystack_builder();
   110→    let unsorted = args
   111→        .walk_builder()?
   112→        .build()
   113→        .filter_map(|result| haystack_builder.build_from_result(result));
   114→    let haystacks = args.sort(unsorted);
   115→
   116→    let mut matched = false;
   117→    let mut searched = false;
   118→    let mut stats = args.stats();
   119→    let mut searcher = args.search_worker(
   120→        args.matcher()?,
   121→        args.searcher()?,
   122→        args.printer(mode, args.stdout()),
   123→    )?;
