   153→/// The top-level entry point for multi-threaded search.
   154→///
   155→/// The parallelism is itself achieved by the recursive directory traversal.
   156→/// All we need to do is feed it a worker for performing a search on each file.
   157→///
   158→/// Requesting a sorted output from ripgrep (such as with `--sort path`) will
   159→/// automatically disable parallelism and hence sorting is not handled here.
   160→fn search_parallel(args: &HiArgs, mode: SearchMode) -> anyhow::Result<bool> {
   161→    use std::sync::atomic::{AtomicBool, Ordering};
   162→
   163→    let started_at = std::time::Instant::now();
   164→    let haystack_builder = args.haystack_builder();
   165→    let bufwtr = args.buffer_writer();
   166→    let stats = args.stats().map(std::sync::Mutex::new);
   167→    let matched = AtomicBool::new(false);
   168→    let searched = AtomicBool::new(false);
   169→
   170→    let mut searcher = args.search_worker(
   171→        args.matcher()?,
   172→        args.searcher()?,
   173→        args.printer(mode, bufwtr.buffer()),
   174→    )?;
   175→    args.walk_builder()?.build_parallel().run(|| {
   176→        let bufwtr = &bufwtr;
   177→        let stats = &stats;
   178→        let matched = &matched;
   179→        let searched = &searched;
   180→        let haystack_builder = &haystack_builder;
   181→        let mut searcher = searcher.clone();
   182→
   183→        Box::new(move |result| {
   184→            let haystack = match haystack_builder.build_from_result(result) {
   185→                Some(haystack) => haystack,
   186→                None => return WalkState::Continue,
   187→            };
   188→            searched.store(true, Ordering::SeqCst);
   189→            searcher.printer().get_mut().clear();
   190→            let search_result = match searcher.search(&haystack) {
   191→                Ok(search_result) => search_result,
   192→                Err(err) => {
   193→                    err_message!("{}: {}", haystack.path().display(), err);
   194→                    return WalkState::Continue;
   195→                }
   196→            };
   197→            if search_result.has_match() {
   198→                matched.store(true, Ordering::SeqCst);
   199→            }
   200→            if let Some(ref locked_stats) = *stats {
   201→                let mut stats = locked_stats.lock().unwrap();
   202→                *stats += search_result.stats().unwrap();
   203→            }
   204→            if let Err(err) = bufwtr.print(searcher.printer().get_mut()) {
   205→                // A broken pipe means graceful termination.
   206→                if err.kind() == std::io::ErrorKind::BrokenPipe {
   207→                    return WalkState::Quit;
   208→                }
   209→                // Otherwise, we continue on our merry way.
   210→                err_message!("{}: {}", haystack.path().display(), err);
   211→            }
   212→            if matched.load(Ordering::SeqCst) && args.quit_after_match() {
   213→                WalkState::Quit
   214→            } else {
   215→                WalkState::Continue
   216→            }
   217→        })
   218→    });
   219→    if args.has_implicit_path() && !searched.load(Ordering::SeqCst) {
   220→        eprint_nothing_searched();
   221→    }
   222→    if let Some(ref locked_stats) = stats {
   223→        let stats = locked_stats.lock().unwrap();
   224→        let mut wtr = searcher.printer().get_mut();
   225→        let _ = print_stats(mode, &stats, started_at, &mut wtr);
   226→        let _ = bufwtr.print(&mut wtr);
   227→    }
   228→    Ok(matched.load(Ordering::SeqCst))
   229→}
