   231→/// The top-level entry point for file listing without searching.
   232→///
   233→/// This recursively steps through the file list (current directory by default)
   234→/// and prints each path sequentially using a single thread.
   235→fn files(args: &HiArgs) -> anyhow::Result<bool> {
   236→    let haystack_builder = args.haystack_builder();
   237→    let unsorted = args
   238→        .walk_builder()?
   239→        .build()
   240→        .filter_map(|result| haystack_builder.build_from_result(result));
   241→    let haystacks = args.sort(unsorted);
   242→
   243→    let mut matched = false;
   244→    let mut path_printer = args.path_printer_builder().build(args.stdout());
   245→    for haystack in haystacks {
   246→        matched = true;
   247→        if args.quit_after_match() {
   248→            break;
   249→        }
   250→        if let Err(err) = path_printer.write(haystack.path()) {
   251→            // A broken pipe means graceful termination.
   252→            if err.kind() == std::io::ErrorKind::BrokenPipe {
   253→                break;
   254→            }
   255→            // Otherwise, we have some other error that's preventing us from
   256→            // writing to stdout, so we should bubble it up.
   257→            return Err(err.into());
   258→        }
   259→    }
   260→    Ok(matched)
   261→}
