   263→/// The top-level entry point for multi-threaded file listing without
   264→/// searching.
   265→///
   266→/// This recursively steps through the file list (current directory by default)
   267→/// and prints each path sequentially using multiple threads.
   268→///
   269→/// Requesting a sorted output from ripgrep (such as with `--sort path`) will
   270→/// automatically disable parallelism and hence sorting is not handled here.
   271→fn files_parallel(args: &HiArgs) -> anyhow::Result<bool> {
   272→    use std::{
   273→        sync::{
   274→            atomic::{AtomicBool, Ordering},
   275→            mpsc,
   276→        },
   277→        thread,
   278→    };
   279→
   280→    let haystack_builder = args.haystack_builder();
   281→    let mut path_printer = args.path_printer_builder().build(args.stdout());
   282→    let matched = AtomicBool::new(false);
   283→    let (tx, rx) = mpsc::channel::<crate::haystack::Haystack>();
   284→
   285→    // We spawn a single printing thread to make sure we don't tear writes.
   286→    // We use a channel here under the presumption that it's probably faster
   287→    // than using a mutex in the worker threads below, but this has never been
   288→    // seriously litigated.
   289→    let print_thread = thread::spawn(move || -> std::io::Result<()> {
   290→        for haystack in rx.iter() {
   291→            path_printer.write(haystack.path())?;
   292→        }
   293→        Ok(())
   294→    });
   295→    args.walk_builder()?.build_parallel().run(|| {
   296→        let haystack_builder = &haystack_builder;
   297→        let matched = &matched;
   298→        let tx = tx.clone();
   299→
   300→        Box::new(move |result| {
   301→            let haystack = match haystack_builder.build_from_result(result) {
   302→                Some(haystack) => haystack,
   303→                None => return WalkState::Continue,
   304→            };
   305→            matched.store(true, Ordering::SeqCst);
   306→            if args.quit_after_match() {
   307→                WalkState::Quit
   308→            } else {
   309→                match tx.send(haystack) {
   310→                    Ok(_) => WalkState::Continue,
   311→                    Err(_) => WalkState::Quit,
   312→                }
   313→            }
   314→        })
   315→    });
   316→    drop(tx);
   317→    if let Err(err) = print_thread.join().unwrap() {
   318→        // A broken pipe means graceful termination, so fall through.
   319→        // Otherwise, something bad happened while writing to stdout, so bubble
   320→        // it up.
   321→        if err.kind() != std::io::ErrorKind::BrokenPipe {
   322→            return Err(err.into());
   323→        }
   324→    }
   325→    Ok(matched.load(Ordering::SeqCst))
   326→}
