   328→/// The top-level entry point for `--type-list`.
   329→fn types(args: &HiArgs) -> anyhow::Result<ExitCode> {
   330→    let mut count = 0;
   331→    let mut stdout = args.stdout();
   332→    for def in args.types().definitions() {
   333→        count += 1;
   334→        stdout.write_all(def.name().as_bytes())?;
   335→        stdout.write_all(b": ")?;
   336→
   337→        let mut first = true;
   338→        for glob in def.globs() {
   339→            if !first {
   340→                stdout.write_all(b", ")?;
   341→            }
   342→            stdout.write_all(glob.as_bytes())?;
   343→            first = false;
   344→        }
   345→        stdout.write_all(b"\n")?;
   346→    }
   347→    Ok(ExitCode::from(if count == 0 { 1 } else { 0 }))
   348→}
