   352→/// These modes correspond to generating some kind of ancillary data related
   353→/// to ripgrep. At present, this includes ripgrep's man page (in roff format)
   354→/// and supported shell completions.
   355→fn generate(mode: crate::flags::GenerateMode) -> anyhow::Result<ExitCode> {
   356→    use crate::flags::GenerateMode;
   357→
   358→    let output = match mode {
   359→        GenerateMode::Man => flags::generate_man_page(),
   360→        GenerateMode::CompleteBash => flags::generate_complete_bash(),
   361→        GenerateMode::CompleteZsh => flags::generate_complete_zsh(),
   362→        GenerateMode::CompleteFish => flags::generate_complete_fish(),
   363→        GenerateMode::CompletePowerShell => {
   364→            flags::generate_complete_powershell()
   365→        }
