   371→/// Implements ripgrep's "special" modes.
   372→///
   373→/// A special mode is one that generally short-circuits most (not all) of
   374→/// ripgrep's initialization logic and skips right to this routine. The
   375→/// special modes essentially consist of printing help and version output. The
   376→/// idea behind the short circuiting is to ensure there is as little as possible
   377→/// (within reason) that would prevent ripgrep from emitting help output.
   378→///
   379→/// For example, part of the initialization logic that is skipped (among
   380→/// other things) is accessing the current working directory. If that fails,
   381→/// ripgrep emits an error. We don't want to emit an error if it fails and
   382→/// the user requested version or help information.
   383→fn special(mode: crate::flags::SpecialMode) -> anyhow::Result<ExitCode> {
   384→    use crate::flags::SpecialMode;
   385→
   386→    let mut exit = ExitCode::from(0);
   387→    let output = match mode {
   388→        SpecialMode::HelpShort => flags::generate_help_short(),
   389→        SpecialMode::HelpLong => flags::generate_help_long(),
   390→        SpecialMode::VersionShort => flags::generate_version_short(),
   391→        SpecialMode::VersionLong => flags::generate_version_long(),
   392→        // --pcre2-version is a little special because it emits an error
   393→        // exit code if this build of ripgrep doesn't support PCRE2.
   394→        SpecialMode::VersionPCRE2 => {
   395→            let (output, available) = flags::generate_version_pcre2();
   396→            if !available {
   397→                exit = ExitCode::from(1);
   398→            }
   399→            output
   400→        }
   401→    };
   402→    writeln!(std::io::stdout(), "{}", output.trim_end())?;
   403→    Ok(exit)
   404→}
