   422→/// Prints the statistics given to the writer given.
   423→///
   424→/// The search mode given determines whether the stats should be printed in
   425→/// a plain text format or in a JSON format.
   426→///
   427→/// The `started` time should be the time at which ripgrep started working.
   428→///
   429→/// If an error occurs while writing, then writing stops and the error is
   430→/// returned. Note that callers should probably ignore this errror, since
   431→/// whether stats fail to print or not generally shouldn't cause ripgrep to
   432→/// enter into an "error" state. And usually the only way for this to fail is
   433→/// if writing to stdout itself fails.
   434→fn print_stats<W: Write>(
   435→    mode: SearchMode,
   436→    stats: &grep::printer::Stats,
   437→    started: std::time::Instant,
   438→    mut wtr: W,
   439→) -> std::io::Result<()> {
   440→    let elapsed = std::time::Instant::now().duration_since(started);
