   443→        // the grep-printer crate. We simply "extend" it with the 'summary'
   444→        // message type.
   445→        serde_json::to_writer(
   446→            &mut wtr,
   447→            &serde_json::json!({
   448→                "type": "summary",
   449→                "data": {
   450→                    "stats": stats,
   451→                    "elapsed_total": {
   452→                        "secs": elapsed.as_secs(),
   453→                        "nanos": elapsed.subsec_nanos(),
   454→                        "human": format!("{:0.6}s", elapsed.as_secs_f64()),
   455→                    },
   456→                }
   457→            }),
   458→        )?;
   459→        write!(wtr, "\n")
   460→    } else {
   461→        write!(
   462→            wtr,
   463→            "
   464→{matches} matches
   465→{lines} matched lines
   466→{searches_with_match} files contained matches
   467→{searches} files searched
   468→{bytes_printed} bytes printed
   469→{bytes_searched} bytes searched
   470→{search_time:0.6} seconds spent searching
   471→{process_time:0.6} seconds total
